// MarketcenterServer is the server API for Marketcenter service.
// All implementations must embed UnimplementedMarketcenterServer
// for forward compatibility.
//
// Marketcenter服务定义
// 提供市场中心相关功能，包括市场查询、市场交易等
type MarketcenterServer interface {
	GetPayMasterData(context.Context, *GetPayMasterDataRequest) (*GetPayMasterDataResponse, error)
	UpdateUserMarketFollowStatus(context.Context, *UpdateUserMarketFollowStatusRequest) (*UpdateUserMarketFollowStatusResponse, error)
	PlaceOrder(context.Context, *PlaceOrderRequest) (*PlaceOrderResponse, error)
	ClaimMarketResult(context.Context, *ClaimMarketResultRequest) (*ClaimMarketResultResponse, error)
	TransferBaseToken(context.Context, *TransferBaseTokenRequest) (*TransferBaseTokenResponse, error)
	GetOptionTokensPrice(context.Context, *GetOptionTokensPriceRequest) (*GetOptionTokensPriceResponse, error)
	// 获取某市场下用户的持仓情况
	GetMarketUsersPositions(context.Context, *GetMarketUsersPositionsRequest) (*GetMarketUsersPositionsResponse, error)
	GetHotMarkets(context.Context, *GetHotMarketsRequest) (*GetHotMarketsResponse, error)
	GetFollowedMarkets(context.Context, *GetFollowedMarketsRequest) (*GetFollowedMarketsResponse, error)
	// 获取用户有持仓的市场信息
	GetHoldingPositionsMarkets(context.Context, *GetHoldingPositionsMarketsRequest) (*GetHoldingPositionsMarketsResponse, error)
	GetMarketDetail(context.Context, *GetMarketDetailRequest) (*GetMarketDetailResponse, error)
	GetMarketTrades(context.Context, *GetMarketTradesRequest) (*GetMarketTradesResponse, error)
	GetUserPositions(context.Context, *GetUserPositionsRequest) (*GetUserPositionsResponse, error)
	GetUserTrades(context.Context, *GetUserTradesRequest) (*GetUserTradesResponse, error)
	GetUserLatestAssetValue(context.Context, *GetUserLatestAssetValueRequest) (*GetUserLatestAssetValueResponse, error)
	SearchMarket(context.Context, *SearchMarketRequest) (*SearchMarketResponse, error)
	GetUserAssetHistory(context.Context, *GetUserAssetHistoryRequest) (*GetUserAssetHistoryResponse, error)
	GetMarketOptionPriceHistory(context.Context, *GetMarketOptionPriceHistoryRequest) (*GetMarketOptionPriceHistoryResponse, error)
	GetMarketTags(context.Context, *GetMarketTagsRequest) (*GetMarketTagsResponse, error)
	GetMarketCategories(context.Context, *GetMarketCategoriesRequest) (*GetMarketCategoriesResponse, error)
	// 分页获取市场信息
	GetMarketsAndOptionsInfo(context.Context, *GetMarketsAndOptionsInfoRequest) (*GetMarketsAndOptionsInfoResponse, error)
	// 批量查询市场用户的持仓
	BatchGetMarketUsersPositions(context.Context, *BatchGetMarketUsersPositionsRequest) (*BatchGetMarketUsersPositionsResponse, error)
	// 爬块监听链上事件后调用
	GetMarketsAndOptionsForBlockListener(context.Context, *GetMarketsAndOptionsForBlockListenerRequest) (*GetMarketsAndOptionsForBlockListenerResponse, error)
	CreateMarketsAndOptions(context.Context, *CreateMarketsAndOptionsRequest) (*CreateMarketsAndOptionsResponse, error)
	ProcessMarketDepositOrWithdrawEvent(context.Context, *ProcessMarketDepositOrWithdrawEventRequest) (*ProcessMarketDepositOrWithdrawEventResponse, error)
	ProcessMarketSwapEvent(context.Context, *ProcessMarketSwapEventRequest) (*ProcessMarketSwapEventResponse, error)
	ProcessMarketClaimResultEvent(context.Context, *ProcessMarketClaimResultEventRequest) (*ProcessMarketClaimResultEventResponse, error)
	ProcessMarketSettingEvent(context.Context, *ProcessMarketSettingEventRequest) (*ProcessMarketSettingEventResponse, error)
	ProcessMarketAssertDisputedEvent(context.Context, *ProcessMarketAssertDisputedEventRequest) (*ProcessMarketAssertDisputedEventResponse, error)
	ProcessMarketAssertionResolvedEvent(context.Context, *ProcessMarketAssertionResolvedEventRequest) (*ProcessMarketAssertionResolvedEventResponse, error)
	UpdateUserBaseTokenBalance(context.Context, *UpdateUserBaseTokenBalanceRequest) (*UpdateUserBaseTokenBalanceResponse, error)
	BatchUpdateOptionPrice(context.Context, *BatchUpdateOptionPriceRequest) (*BatchUpdateOptionPriceResponse, error)
	UpdateMarketStatus(context.Context, *UpdateMarketStatusRequest) (*UpdateMarketStatusResponse, error)
	UpdateMarketInfo(context.Context, *UpdateMarketInfoRequest) (*UpdateMarketInfoResponse, error)
	GetUserTransactions(context.Context, *GetUserTransactionsRequest) (*GetUserTransactionsResponse, error)
	GetBanners(context.Context, *GetBannersRequest) (*GetBannersResponse, error)
	GetSections(context.Context, *GetSectionsRequest) (*GetSectionsResponse, error)
	GetLeaderboard(context.Context, *GetLeaderboardRequest) (*GetLeaderboardResponse, error)
	GetQuestionDetail(context.Context, *GetQuestionDetailRequest) (*GetQuestionDetailResponse, error)
	// CTF Event 相关
	GetEvent(context.Context, *GetEventRequest) (*GetEventResponse, error)
	ListEvents(context.Context, *ListEventsRequest) (*ListEventsResponse, error)
	CreateEvent(context.Context, *CreateEventRequest) (*CreateEventResponse, error)
	// CTF APMM 交易接口
	CTFSwap(context.Context, *CTFSwapRequest) (*CTFSwapResponse, error)
	CTFDepositLiquidity(context.Context, *CTFDepositLiquidityRequest) (*CTFDepositLiquidityResponse, error)
	CTFWithdrawLiquidity(context.Context, *CTFWithdrawLiquidityRequest) (*CTFWithdrawLiquidityResponse, error)
	CTFRedeemPosition(context.Context, *CTFRedeemPositionRequest) (*CTFRedeemPositionResponse, error)
	CTFGetSwapPrice(context.Context, *CTFGetSwapPriceRequest) (*CTFGetSwapPriceResponse, error)
	// CTF 链上事件处理 (block-listener → market-service)
	ProcessCTFConditionEvent(context.Context, *ProcessCTFConditionEventRequest) (*ProcessCTFConditionEventResponse, error)
	ProcessCTFPositionEvent(context.Context, *ProcessCTFPositionEventRequest) (*ProcessCTFPositionEventResponse, error)
	ProcessCTFTransferEvent(context.Context, *ProcessCTFTransferEventRequest) (*ProcessCTFTransferEventResponse, error)
	ProcessCTFMarketResolvedEvent(context.Context, *ProcessCTFMarketResolvedEventRequest) (*ProcessCTFMarketResolvedEventResponse, error)
	ProcessCTFLiquidityEvent(context.Context, *ProcessCTFLiquidityEventRequest) (*ProcessCTFLiquidityEventResponse, error)
	mustEmbedUnimplementedMarketcenterServer()
}

